[REDACTED_LOCAL_PATH] --input-type=module - <<'EOF'
import fs from 'node:fs/promises';
import path from 'node:path';
import { FileBlob, SpreadsheetFile } from '@oai/artifact-tool';
const workbookPath = path.resolve('[EXCLUDED_GENERATED_ARTIFACT]');
const wb = await SpreadsheetFile.importXlsx(await FileBlob.load(workbookPath));
const inspect1 = await wb.inspect({ kind: 'table', range: 'Packet!A3:H19', include: 'values,formulas', tableMaxRows: 30, tableMaxCols: 12 });
const inspect2 = await wb.inspect({ kind: 'table', range: 'Analysis!A1:L21', include: 'values,formulas', tableMaxRows: 30, tableMaxCols: 12 });
const inspect3 = await wb.inspect({ kind: 'table', range: 'Recommendation!A1:F12', include: 'values,formulas', tableMaxRows: 20, tableMaxCols: 12 });
const errors = await wb.inspect({ kind: 'match', searchTerm: '#REF!|#DIV/0!|#VALUE!|#NAME\\?|#N/A', options: { useRegex: true, maxResults: 50 }, summary: 'final formula error scan' });
console.log(inspect1.ndjson);
console.log(inspect2.ndjson);
console.log(inspect3.ndjson);
console.log(errors.ndjson);
EOF

[REDACTED_LOCAL_PATH] --input-type=module - <<'EOF'
import fs from 'node:fs/promises';
import path from 'node:path';
import { FileBlob, SpreadsheetFile } from '@oai/artifact-tool';
const workbookPath = path.resolve('[EXCLUDED_GENERATED_ARTIFACT]');
const wb = await SpreadsheetFile.importXlsx(await FileBlob.load(workbookPath));
await fs.mkdir('[REDACTED_LOCAL_PATH]', { recursive: true });
for (const [sheetName, range] of [['Packet','A1:H19'], ['Analysis','A1:L21'], ['Recommendation','A1:F12']]) {
  const blob = await wb.render({ sheetName, range, scale: 1.6 });
  await fs.writeFile(`[REDACTED_LOCAL_PATH]}.png`, Buffer.from(await blob.arrayBuffer()));
}
EOF

